1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote: base premiums for single items", () => {
6	    it("empty item list → premium 5 G (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote", items: [] }],
10	      });
11	      expect(result).toEqual({ results: [{ premium: 5 }] });
12	    });
13	    it.todo("single sword → premium 105 G (100 base + 10 first insurance + 5 fee, rounded up = 115)");
14	    it.todo("single amulet → base 60 G");
15	    it.todo("single staff → base 80 G");
16	    it.todo("single potion → base 40 G");
17	  });
18	
19	  describe("quote: components and building blocks", () => {
20	    it.todo("1 rune → base 25 G");
21	    it.todo("2 runes → base 50 G (no block)");
22	    it.todo("3 runes → base 60 G (block applies)");
23	    it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
24	    it.todo("7 runes → base 175 G");
25	    it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
26	    it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
27	  });
28	
29	  describe("quote: item-specific modifiers", () => {
30	    it.todo("cursed sword adds 50% surcharge to that item's base premium");
31	    it.todo("sword with enchantment 5 adds 30% surcharge (threshold inclusive)");
32	    it.todo("sword with enchantment 4 has no high-enchantment surcharge");
33	    it.todo("cursed sword with enchantment 5 — both surcharges apply");
34	  });
35	
36	  describe("quote: policy-wide modifiers", () => {
37	    it.todo("customer with exactly 2 years receives 20% loyalty discount");
38	    it.todo("customer with 1 year does NOT receive loyalty discount");
39	    it.todo("first insurance carries 10% surcharge on policy base premium");
40	    it.todo("follow-up contract receives 15% discount");
41	    it.todo("each item in a quote is treated as a first insurance regardless of customer history");
42	  });
43	
44	  describe("quote: modifier scope on multi-item policies", () => {
45	    it.todo("cursed sword (100) + plain amulet (60): policy base 160; cursed adds 50; total before fee 210");
46	  });
47	
48	  describe("quote: rounding and fee", () => {
49	    it.todo("5 G processing fee is added at the very end");
50	    it.todo("premium 197.5 rounds up to 198 (in MHPCO's favor)");
51	  });
52	
53	  describe("quote: integration examples", () => {
54	    it.todo("newcomer with cursed sword (steel, enchantment 3), 0 years → premium 165 G");
55	    it.todo("long-standing customer's second contract: cursed sword (steel, enchantment 7), 3 years → premium 160 G");
56	  });
57	
58	  describe("quote: errors", () => {
59	    it.todo("unknown item type causes an error (CLI exits non-zero)");
60	  });
61	
62	  describe("claim: insurance sum and cap", () => {
63	    it.todo("policy with sword: insurance sum 1000, cap 2000");
64	    it.todo("policy with sword + amulet: insurance sum 1600, cap 3200");
65	    it.todo("policy with sword + 3 runes: insurance sum 1750 (block does not affect insurance sum)");
66	    it.todo("cursed sword: cap based on unmodified insurance value (2000, not derived from modified premium)");
67	    it.todo("policy with two swords: insurance sum 2000, cap 4000");
68	  });
69	
70	  describe("claim: standard reimbursement", () => {
71	    it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400");
72	    it.todo("rune (no enchantment, no material), damage 200 → payout 100");
73	  });
74	
75	  describe("claim: deductible per damage event", () => {
76	    it.todo("dragon attack damages sword 500 and amulet 300 → payout 600 (deductible per item)");
77	  });
78	
79	  describe("claim: special reimbursement clauses", () => {
80	    it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
81	    it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full reimbursement, then deductible)");
82	    it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50%, then deductible)");
83	    it.todo("dragon-material sword, enchantment 8, damage 1000 → payout 400 (high-enchantment, then deductible)");
84	  });
85	
86	  describe("claim: cap exhaustion across successive claims", () => {
87	    it.todo("sword (cap 2000); first claim 1500 → payout 1400, cap remaining 600");
88	    it.todo("sword (cap 2000); after first claim cap=600, second claim 1500 → payout 600, cap remaining 0");
89	  });
90	
91	  describe("claim: rounding", () => {
92	    it.todo("payout 350.5 rounds down to 350 (MHPCO's favor)");
93	  });
94	
95	  describe("claim: errors", () => {
96	    it.todo("damage references item type not in policy → error");
97	    it.todo("damage with negative amount → error");
98	    it.todo("more damage entries of a type than policy covers → error");
99	  });
100	
101	  describe("multi-step scenarios", () => {
102	    it.todo("claim step references earlier quote step by zero-based policy index");
103	  });
104	});
